module RefModule(
	 clk,    
	 reset,  
	 input_pc,  
	 output_pc, 
	 PCWre   
);input wire[31:0] input_pc;
	 output reg[31:0] output_pc;
	 input clk, reset, PCWre;


	  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt)begin
		if(reset == 0)begin  
			output_pc = 0;
		end
		else if(!PCWre)begin  
			output_pc = output_pc;
		end
		else if(PCWre)begin   
			output_pc = input_pc;
		end
	end

endmodule
